mapper.select:
SELECT COUNT(*)
FROM export_order
WHERE status = #{status}

mapper.update:
UPDATE export_order
SET status = #{status}
WHERE id = #{id}
  AND status != 'DONE'

UPDATE export_order
SET stock_applied = #{stockApplied}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM export_order_detail
WHERE export_order_id = #{exportOrderId}

mapper.update:
UPDATE export_order
SET remark = #{remark},
    status = #{status}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM export_order
WHERE YEAR(created_at) = #{year}
  AND QUARTER(created_at) = #{quarter}
  AND status != 'CANCELLED'

SELECT COUNT(*)
FROM export_order
WHERE YEAR(created_at) = #{year}
  AND QUARTER(created_at) = #{quarter}
  AND status = 'DONE'

SELECT COUNT(*)
FROM export_order
WHERE YEAR(created_at) = #{year}
  AND MONTH(created_at) = #{month}
  AND status != 'CANCELLED'

SELECT COUNT(*)
FROM export_order
WHERE YEAR(created_at) = #{year}
  AND MONTH(created_at) = #{month}
  AND status = 'DONE'

SELECT COUNT(*)
FROM export_order
WHERE YEAR(created_at) = #{year}
  AND WEEK(created_at, 1) = #{week}
  AND status != 'CANCELLED'

SELECT COUNT(*)
FROM export_order
